function DefaultCurrency9110() {}
DefaultCurrency9110.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency9110.tabIndex = -1;
DefaultCurrency9110.maxLength = 1;
DefaultCurrency9110.isReadOnly = function(){return true;}
DefaultCurrency9110.isTemporary = function(){return true;}
DefaultCurrency9110.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency9110.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
